### 2. Add delivery tests to `packages/relay/src/adapters/telegram/__tests__/outbound.test.ts`

The current test file only covers typing indicators. Add comprehensive `deliverMessage` tests. The mock setup needs to be extended:

```typescript
import { deliverMessage, handleTypingSignal, clearAllTypingIntervals } from '../outbound.js';
import type { Bot } from 'grammy';
import type { AdapterOutboundCallbacks } from '../../../types.js';

// Add payload-utils mock (no SILENT_EVENT_TYPES):
vi.mock('../../../lib/payload-utils.js', () => ({
  extractPayloadContent: (payload: unknown) => {
    if (typeof payload === 'string') return payload;
    if (payload !== null && typeof payload === 'object') {
      const obj = payload as Record<string, unknown>;
      if (typeof obj.content === 'string') return obj.content;
      if (typeof obj.text === 'string') return obj.text;
    }
    try { return JSON.stringify(payload); } catch { return '[unserializable payload]'; }
  },
  detectStreamEventType: (payload: unknown) => {
    if (payload === null || typeof payload !== 'object') return null;
    const obj = payload as Record<string, unknown>;
    if (typeof obj.type !== 'string' || !('data' in obj)) return null;
    return obj.type;
  },
  extractTextDelta: (payload: unknown) => {
    if (payload === null || typeof payload !== 'object') return null;
    const obj = payload as Record<string, unknown>;
    if (obj.type !== 'text_delta') return null;
    const data = obj.data as Record<string, unknown> | undefined;
    if (!data || typeof data.text !== 'string') return null;
    return data.text;
  },
  extractErrorMessage: (payload: unknown) => {
    if (payload === null || typeof payload !== 'object') return null;
    const obj = payload as Record<string, unknown>;
    if (obj.type !== 'error') return null;
    const data = obj.data as Record<string, unknown> | undefined;
    return typeof data?.message === 'string' ? data.message : null;
  },
  truncateText: (text: string, maxLen: number) => {
    if (text.length <= maxLen) return text;
    return `${text.slice(0, maxLen - 3)}...`;
  },
}));

const mockSendMessage = vi.fn().mockResolvedValue({ message_id: 1 });
```

Extend `buildMockBot()` to include `sendMessage`:
```typescript
function buildMockBot(): Bot {
  return {
    api: {
      sendChatAction: mockSendChatAction,
      sendMessage: mockSendMessage,
    },
  } as unknown as Bot;
}
```

Add these test blocks:

```typescript
function createCallbacks(): AdapterOutboundCallbacks {
  return {
    trackOutbound: vi.fn(),
    recordError: vi.fn(),
  };
}

function createEnvelope(subject: string, payload: unknown, from = 'relay.agent.backend') {
  return {
    id: 'env-01',
    subject,
    from,
    budget: {
      hopCount: 0,
      maxHops: 5,
      ancestorChain: [],
      ttl: Date.now() + 3_600_000,
      callBudgetRemaining: 10,
    },
    createdAt: new Date().toISOString(),
    payload,
  };
}

describe('deliverMessage', () => {
  let bot: Bot;
  let responseBuffers: Map<number, string>;
  let callbacks: AdapterOutboundCallbacks;

  beforeEach(() => {
    vi.clearAllMocks();
    bot = buildMockBot();
    responseBuffers = new Map();
    callbacks = createCallbacks();
  });

  describe('echo prevention', () => {
    it('skips envelopes from relay.human.telegram.* (echo prevention)', async () => {
      const envelope = createEnvelope(
        'relay.human.telegram.12345',
        { content: 'echo' },
        'relay.human.telegram.bot',
      );
      const result = await deliverMessage({
        adapterId: 'telegram',
        subject: 'relay.human.telegram.12345',
        envelope,
        bot,
        responseBuffers,
        callbacks,
      });
      expect(result.success).toBe(true);
      expect(mockSendMessage).not.toHaveBeenCalled();
    });
  });

  describe('guard conditions', () => {
    it('returns error when bot is null', async () => {
      const envelope = createEnvelope('relay.human.telegram.12345', { content: 'hi' });
      const result = await deliverMessage({
        adapterId: 'telegram',
        subject: 'relay.human.telegram.12345',
        envelope,
        bot: null,
        responseBuffers,
        callbacks,
      });
      expect(result.success).toBe(false);
      expect(result.error).toContain('not started');
    });

    it('returns error when subject has no extractable chat ID', async () => {
      const envelope = createEnvelope('relay.human.slack.D123', { content: 'hi' });
      const result = await deliverMessage({
        adapterId: 'telegram',
        subject: 'relay.human.slack.D123',
        envelope,
        bot,
        responseBuffers,
        callbacks,
      });
      expect(result.success).toBe(false);
      expect(result.error).toContain('cannot extract chat ID');
    });
  });

  describe('standard payload delivery', () => {
    it('sends standard payload via sendMessage', async () => {
      const envelope = createEnvelope('relay.human.telegram.12345', { content: 'Hello!' });
      const result = await deliverMessage({
        adapterId: 'telegram',
        subject: 'relay.human.telegram.12345',
        envelope,
        bot,
        responseBuffers,
        callbacks,
      });
      expect(result.success).toBe(true);
      expect(mockSendMessage).toHaveBeenCalledWith(12345, 'Hello!');
      expect(callbacks.trackOutbound).toHaveBeenCalled();
    });
  });

  describe('streaming — text_delta buffering', () => {
    it('buffers text_delta events without sending', async () => {
      const envelope = createEnvelope('relay.human.telegram.12345', {
        type: 'text_delta', data: { text: 'Hello' },
      });
      const result = await deliverMessage({
        adapterId: 'telegram',
        subject: 'relay.human.telegram.12345',
        envelope,
        bot,
        responseBuffers,
        callbacks,
      });
      expect(result.success).toBe(true);
      expect(mockSendMessage).not.toHaveBeenCalled();
      expect(responseBuffers.get(12345)).toBe('Hello');
    });

    it('accumulates multiple text_delta events', async () => {
      for (const text of ['Hello', ' world', '!']) {
        const envelope = createEnvelope('relay.human.telegram.12345', {
          type: 'text_delta', data: { text },
        });
        await deliverMessage({
          adapterId: 'telegram',
          subject: 'relay.human.telegram.12345',
          envelope,
          bot,
          responseBuffers,
          callbacks,
        });
      }
      expect(responseBuffers.get(12345)).toBe('Hello world!');
      expect(mockSendMessage).not.toHaveBeenCalled();
    });
  });

  describe('streaming — done flush', () => {
    it('flushes buffered text on done event', async () => {
      responseBuffers.set(12345, 'Accumulated text');
      const envelope = createEnvelope('relay.human.telegram.12345', {
        type: 'done', data: {},
      });
      const result = await deliverMessage({
        adapterId: 'telegram',
        subject: 'relay.human.telegram.12345',
        envelope,
        bot,
        responseBuffers,
        callbacks,
      });
      expect(result.success).toBe(true);
      expect(mockSendMessage).toHaveBeenCalledWith(12345, 'Accumulated text');
      expect(responseBuffers.has(12345)).toBe(false);
      expect(callbacks.trackOutbound).toHaveBeenCalled();
    });

    it('done with no buffered text does not send', async () => {
      const envelope = createEnvelope('relay.human.telegram.12345', {
        type: 'done', data: {},
      });
      const result = await deliverMessage({
        adapterId: 'telegram',
        subject: 'relay.human.telegram.12345',
        envelope,
        bot,
        responseBuffers,
        callbacks,
      });
      expect(result.success).toBe(true);
      expect(mockSendMessage).not.toHaveBeenCalled();
    });
  });

  describe('streaming — error flush', () => {
    it('flushes buffer with error suffix on error event', async () => {
      responseBuffers.set(12345, 'Partial response');
      const envelope = createEnvelope('relay.human.telegram.12345', {
        type: 'error', data: { message: 'Context exceeded' },
      });
      const result = await deliverMessage({
        adapterId: 'telegram',
        subject: 'relay.human.telegram.12345',
        envelope,
        bot,
        responseBuffers,
        callbacks,
      });
      expect(result.success).toBe(true);
      expect(mockSendMessage).toHaveBeenCalledWith(
        12345,
        expect.stringContaining('[Error: Context exceeded]'),
      );
      expect(responseBuffers.has(12345)).toBe(false);
    });

    it('sends standalone error when no buffer exists', async () => {
      const envelope = createEnvelope('relay.human.telegram.12345', {
        type: 'error', data: { message: 'Session failed' },
      });
      await deliverMessage({
        adapterId: 'telegram',
        subject: 'relay.human.telegram.12345',
        envelope,
        bot,
        responseBuffers,
        callbacks,
      });
      expect(mockSendMessage).toHaveBeenCalledWith(12345, '[Error: Session failed]');
    });
  });

  describe('event whitelist — unknown events silently dropped', () => {
    it.each([
      'thinking_delta',
      'system_status',
      'tool_progress',
      'compact_boundary',
      'subagent_started',
      'subagent_progress',
      'subagent_done',
      'hook_started',
      'hook_progress',
      'hook_response',
      'prompt_suggestion',
      'presence_update',
      'rate_limit',
      'session_status',
      'tool_call_start',
      'tool_call_delta',
      'tool_call_end',
      'tool_result',
      'approval_required',
      'question_prompt',
      'some_future_event_xyz',
    ])('silently drops %s', async (eventType) => {
      const envelope = createEnvelope('relay.human.telegram.12345', {
        type: eventType,
        data: { text: 'internal data' },
      });
      const result = await deliverMessage({
        adapterId: 'telegram',
        subject: 'relay.human.telegram.12345',
        envelope,
        bot,
        responseBuffers,
        callbacks,
      });
      expect(result.success).toBe(true);
      expect(mockSendMessage).not.toHaveBeenCalled();
    });
  });
});
```

## Acceptance Criteria

- Telegram adapter silently drops all unrecognized StreamEvent types (returns `{ success: true }` without calling any Telegram API)
- `SILENT_EVENT_TYPES` is no longer imported in `telegram/outbound.ts`
- Standard (non-StreamEvent) payloads still deliver normally via `bot.api.sendMessage`
- Existing text_delta buffering, error flush, and done flush behavior is unchanged
- Whitelist test covers 21 event types including a fictional `some_future_event_xyz`
- Comprehensive delivery tests added for echo prevention, guard conditions, standard payload, streaming (text_delta/done/error), and whitelist
- `pnpm vitest run packages/relay/src/adapters/telegram/__tests__/outbound.test.ts` passes

## Objective

Add support for Slack's native streaming API (`chat.startStream`/`appendStream`/`stopStream`) as an alternative to the current `chat.update` edit-in-place approach. This provides better rate limits, smoother UX, and is purpose-built for AI streaming.

## Changes

### 1. Add `nativeStreaming` config field to `packages/shared/src/relay-adapter-schemas.ts`

Update `SlackAdapterConfigSchema` to include the new field:

```typescript
export const SlackAdapterConfigSchema = z
  .object({
    botToken: z.string().min(1),
    appToken: z.string().min(1),
    signingSecret: z.string().min(1),
    streaming: z.boolean().default(true),
    nativeStreaming: z.boolean().default(true),
    typingIndicator: z.enum(['none', 'reaction']).default('none'),
  })
  .openapi('SlackAdapterConfig');
```

### 2. Add `nativeStreaming` config field to `packages/relay/src/adapters/slack/slack-adapter.ts`

Add a new config field entry in the `configFields` array in `SLACK_MANIFEST`, and add `nativeStreaming` to the setup step's `fields` array:

```typescript
{
  key: 'nativeStreaming',
  label: 'Native Streaming',
  type: 'boolean',
  required: false,
  description:
    "Use Slack's native streaming API (chat.startStream/appendStream/stopStream). Requires messages in threads.",
  visibleByDefault: true,
  helpMarkdown:
    'When enabled, uses Slack\'s purpose-built streaming API for smoother, flicker-free responses. ' +
    'When disabled, uses the legacy chat.update approach. Only applies when Stream Responses is enabled.',
},
```

Update the `deliver()` method to pass `nativeStreaming` to `deliverMessage`:
```typescript
async deliver(
  subject: string,
  envelope: RelayEnvelope,
  _context?: AdapterContext,
): Promise<DeliveryResult> {
  return deliverMessage({
    adapterId: this.id,
    subject,
    envelope,
    client: this.app?.client ?? null,
    streamState: this.streamState,
    botUserId: this.botUserId,
    callbacks: this.makeOutboundCallbacks(),
    streaming: this.config.streaming ?? true,
    nativeStreaming: this.config.nativeStreaming ?? true,
    typingIndicator: this.config.typingIndicator ?? 'none',
  });
}
```

### 3. Update `packages/relay/src/adapters/slack/outbound.ts`

Add `nativeStreaming: boolean` to `SlackDeliverOptions`:
```typescript
export interface SlackDeliverOptions {
  adapterId: string;
  subject: string;
  envelope: RelayEnvelope;
  client: WebClient | null;
  streamState: Map<string, ActiveStream>;
  botUserId: string;
  callbacks: AdapterOutboundCallbacks;
  streaming: boolean;
  nativeStreaming: boolean;
  typingIndicator: 'none' | 'reaction';
}
```

Add optional `nativeStreamId` to `ActiveStream`:
```typescript
export interface ActiveStream {
  channelId: string;
  threadTs: string;
  messageTs: string;
  accumulatedText: string;
  lastUpdateAt: number;
  startedAt: number;
  streamId: string;
  /** Slack streaming API stream_id (only set when nativeStreaming is true). */
  nativeStreamId?: string;
}
```

Modify `handleTextDelta` to accept a `nativeStreaming` parameter. When `nativeStreaming` is true AND `streaming` is true:

**First `text_delta` (no existing stream):**
```typescript
if (nativeStreaming && threadTs) {
  try {
    const result = await (client as any).chat.startStream({
      channel: channelId,
      thread_ts: threadTs,
    });
    const nativeStreamId = (result as { stream_id?: string }).stream_id ?? '';
    streamState.set(key, {
      channelId,
      threadTs: threadTs ?? '',
      messageTs: '', // Not used in native streaming
      accumulatedText: textChunk,
      lastUpdateAt: Date.now(),
      startedAt: Date.now(),
      streamId: randomUUID(),
      nativeStreamId,
    });
    // Append the first chunk
    await (client as any).chat.appendStream({
      stream_id: nativeStreamId,
      text: formatForPlatform(textChunk, 'slack'),
    });
    addTypingReaction(client, channelId, threadTs, typingIndicator);
    return { success: true, durationMs: Date.now() - startTime };
  } catch (err) {
    // Fallback to chat.update approach for this stream
    // (e.g., missing scope, API not available)
    callbacks.recordError(err);
    // Fall through to existing chat.postMessage logic
  }
}
```

**Subsequent `text_delta` (existing stream with `nativeStreamId`):**
```typescript
if (existing.nativeStreamId) {
  existing.accumulatedText += textChunk;
  // No throttling needed for native streaming — API is designed for high-frequency appends
  return wrapSlackCall(
    () => (client as any).chat.appendStream({
      stream_id: existing.nativeStreamId,
      text: formatForPlatform(textChunk, 'slack'),
    }),
    callbacks,
    startTime,
  );
}
```

Modify `handleDone` for native streaming:
```typescript
if (existing.nativeStreamId) {
  removeTypingReaction(client, channelId, existing.threadTs, typingIndicator);
  return wrapSlackCall(
    () => (client as any).chat.stopStream({
      stream_id: existing.nativeStreamId,
    }),
    callbacks,
    startTime,
    true,
  );
}
```

Modify `handleError` for native streaming:
```typescript
if (existing?.nativeStreamId) {
  removeTypingReaction(client, channelId, existing.threadTs, typingIndicator);
  const errorSuffix = formatForPlatform(`\n\n[Error: ${errorMsg}]`, 'slack');
  try {
    await (client as any).chat.appendStream({
      stream_id: existing.nativeStreamId,
      text: errorSuffix,
    });
  } catch { /* best-effort append */ }
  return wrapSlackCall(
    () => (client as any).chat.stopStream({
      stream_id: existing.nativeStreamId,
    }),
    callbacks,
    startTime,
    true,
  );
}
```

### 4. Add native streaming tests to `packages/relay/src/adapters/slack/__tests__/outbound.test.ts`

Add `startStream`, `appendStream`, `stopStream` mocks to `buildMockClient()`:
```typescript
const mockStartStream = vi.fn().mockResolvedValue({ stream_id: 'stream-123' });
const mockAppendStream = vi.fn().mockResolvedValue({ ok: true });
const mockStopStream = vi.fn().mockResolvedValue({ ok: true });

function buildMockClient(): WebClient {
  const stub = {
    chat: {
      postMessage: mockPostMessage,
      update: mockChatUpdate,
      startStream: mockStartStream,
      appendStream: mockAppendStream,
      stopStream: mockStopStream,
    },
    reactions: { add: mockReactionsAdd, remove: mockReactionsRemove },
  };
  return stub as unknown as WebClient;
}
```

Update the `deliver` helper to accept `nativeStreaming`:
```typescript
function deliver(
  subject: string,
  envelope: ReturnType<typeof createEnvelope>,
  client: WebClient | null,
  streamState: Map<string, ActiveStream>,
  callbacks: AdapterOutboundCallbacks,
  botUserId = 'UBOTID',
  streaming = true,
  typingIndicator: 'none' | 'reaction' = 'none',
  nativeStreaming = false,
) {
  return deliverMessage({
    adapterId: 'slack',
    subject,
    envelope,
    client,
    streamState,
    botUserId,
    callbacks,
    streaming,
    nativeStreaming,
    typingIndicator,
  });
}
```

Add test block:
```typescript
describe('native streaming — chat.startStream/appendStream/stopStream', () => {
  it('starts stream on first text_delta', async () => {
    const delta = createEnvelope('relay.human.slack.D123', {
      type: 'text_delta',
      data: { text: 'Hello' },
      platformData: { ts: '1234.0001' },
    });
    await deliver('relay.human.slack.D123', delta, client, streamState, callbacks, 'UBOTID', true, 'none', true);
    expect(mockStartStream).toHaveBeenCalledWith(
      expect.objectContaining({ channel: 'D123', thread_ts: '1234.0001' }),
    );
    expect(mockAppendStream).toHaveBeenCalledWith(
      expect.objectContaining({ stream_id: 'stream-123', text: 'Hello' }),
    );
    expect(mockPostMessage).not.toHaveBeenCalled();
  });

  it('appends text on subsequent text_delta', async () => {
    const delta1 = createEnvelope('relay.human.slack.D123', {
      type: 'text_delta',
      data: { text: 'Hello' },
      platformData: { ts: '1234.0001' },
    });
    await deliver('relay.human.slack.D123', delta1, client, streamState, callbacks, 'UBOTID', true, 'none', true);

    const delta2 = createEnvelope('relay.human.slack.D123', {
      type: 'text_delta',
      data: { text: ' world' },
      platformData: { ts: '1234.0001' },
    });
    await deliver('relay.human.slack.D123', delta2, client, streamState, callbacks, 'UBOTID', true, 'none', true);

    expect(mockAppendStream).toHaveBeenCalledTimes(2);
    expect(mockChatUpdate).not.toHaveBeenCalled();
