Modify the `text_delta` handler in `deliverMessage()` to use `sendMessageDraft` when streaming is enabled and chat is a DM:

```typescript
// text_delta: accumulate in buffer
const textChunk = extractTextDelta(envelope.payload);
if (textChunk) {
  const existing = responseBuffers.get(chatId) ?? '';
  responseBuffers.set(chatId, existing + textChunk);

  // Native draft streaming: DMs only (chatId > 0), streaming enabled
  if (opts.streaming && chatId > 0) {
    const now = Date.now();
    const lastUpdate = lastDraftUpdate.get(chatId) ?? 0;
    if (now - lastUpdate >= DRAFT_UPDATE_INTERVAL_MS) {
      lastDraftUpdate.set(chatId, now);
      try {
        await (bot.api as any).sendMessageDraft(chatId, responseBuffers.get(chatId)!);
      } catch {
        // sendMessageDraft not available or failed — fall back to buffer-and-flush
        // Don't disable streaming globally; failure may be transient
      }
    }
  }

  return { success: true, durationMs: Date.now() - startTime };
}
```

